const Sidebar = ({ onOpenEdit }) => {
  const grados = ["4/5", "6/7", "8/9", "10/11"];
  
  return (
    <div className="sidebar" style={{ width: '300px', background: '#e0e0e0', padding: '20px' }}>
      <h3>Preguntas</h3>
      {grados.map(g => (
        <button 
          key={g} 
          onClick={() => onOpenEdit(g)}
          style={{ display: 'block', width: '100%', margin: '10px 0', padding: '15px' }}
        >
          Preguntas para {g}
        </button>
      ))}
    </div>
  );
};

export default Sidebar;
